import pytest


def parse_duration(s: str) -> int:
    """Parse duration string like '2h30m', '45s', '1h', '90m' into total seconds."""
    import re
    total = 0
    for val, unit in re.findall(r'(\d+)([hms])', s):
        if unit == 'h': total += int(val) * 3600
        elif unit == 'm': total += int(val) * 60
        elif unit == 's': total += int(val)
    return total


class TestParseDuration:
    # Single unit tests
    def test_single_hour(self):
        assert parse_duration('1h') == 3600

    def test_single_minute(self):
        assert parse_duration('1m') == 60

    def test_single_second(self):
        assert parse_duration('1s') == 1

    def test_multiple_hours(self):
        assert parse_duration('5h') == 18000

    def test_multiple_minutes(self):
        assert parse_duration('45m') == 2700

    def test_multiple_seconds(self):
        assert parse_duration('45s') == 45

    def test_large_minutes(self):
        assert parse_duration('90m') == 5400

    # Combined units
    def test_hours_and_minutes(self):
        assert parse_duration('2h30m') == 2 * 3600 + 30 * 60

    def test_hours_minutes_seconds(self):
        assert parse_duration('1h2m3s') == 3600 + 120 + 3

    def test_minutes_and_seconds(self):
        assert parse_duration('5m30s') == 330

    def test_hours_and_seconds(self):
        assert parse_duration('1h30s') == 3630

    # Edge cases
    def test_empty_string(self):
        assert parse_duration('') == 0

    def test_no_valid_units(self):
        assert parse_duration('abc') == 0

    def test_only_digits_no_unit(self):
        assert parse_duration('123') == 0

    def test_only_unit_no_digits(self):
        assert parse_duration('hms') == 0

    def test_zero_hours(self):
        assert parse_duration('0h') == 0

    def test_zero_minutes(self):
        assert parse_duration('0m') == 0

    def test_zero_seconds(self):
        assert parse_duration('0s') == 0

    def test_all_zeros(self):
        assert parse_duration('0h0m0s') == 0

    def test_large_value(self):
        assert parse_duration('100h') == 360000

    def test_very_large_value(self):
        assert parse_duration('9999h') == 9999 * 3600

    # Mixed / unusual input (function tolerates garbage)
    def test_with_spaces_between(self):
        # Regex still matches digit+unit pairs
        assert parse_duration('1h 30m') == 3600 + 1800

    def test_with_garbage_characters(self):
        assert parse_duration('foo1h bar30m baz') == 3600 + 1800

    def test_repeated_units_sums(self):
        # Function sums duplicates
        assert parse_duration('1h1h') == 7200

    def test_uppercase_ignored(self):
        # Regex is lowercase only
        assert parse_duration('1H30M') == 0

    def test_mixed_case_partial(self):
        assert parse_duration('1H30m') == 1800

    def test_unit_without_number_ignored(self):
        assert parse_duration('h30m') == 1800

    def test_order_does_not_matter(self):
        # Function just sums, order doesn't matter
        assert parse_duration('30s2h') == 2 * 3600 + 30

    def test_leading_zeros(self):
        assert parse_duration('01h05m') == 3600 + 300

    def test_negative_sign_ignored(self):
        # Regex won't capture negative sign, so '-' is ignored
        assert parse_duration('-1h') == 3600

    def test_decimal_not_supported(self):
        # '1.5h' -> '1' matches with 'h', then '5' no unit
        assert parse_duration('1.5h') == 3600

    def test_other_units_ignored(self):
        assert parse_duration('1d2h') == 7200

    # Type checks
    def test_return_type_is_int(self):
        assert isinstance(parse_duration('1h'), int)

    def test_return_type_empty(self):
        assert isinstance(parse_duration(''), int)


@pytest.mark.parametrize("input_str,expected", [
    ('1h', 3600),
    ('1m', 60),
    ('1s', 1),
    ('2h30m', 9000),
    ('1h2m3s', 3723),
    ('', 0),
    ('0h0m0s', 0),
    ('90m', 5400),
    ('45s', 45),
    ('10h10m10s', 36610),
])
def test_parse_duration_parametrized(input_str, expected):
    assert parse_duration(input_str) == expected
